import anthropic, json

client = anthropic.Anthropic()

SYSTEM = """You are a customer service agent for AcmeCorp.
- Use the get_order tool before discussing any order status
- Never discuss competitor products or internal pricing
- Keep responses under 100 words"""

tools = [{
    "name": "get_order",
    "description": "Retrieve order status by order ID",
    "input_schema": {
        "type": "object",
        "properties": {"order_id": {"type": "string"}},
        "required": ["order_id"],
    },
}]

def fake_get_order(order_id):
    return {"order_id": order_id, "status": "shipped", "eta": "2024-02-10"}

def run_agent(user_message: str) -> str:
    messages = [{"role": "user", "content": user_message}]
    while True:
        resp = client.messages.create(
            model="claude-haiku-4-5-20251001",
            max_tokens=512,
            system=SYSTEM,
            tools=tools,
            messages=messages,
        )
        if resp.stop_reason == "end_turn":
            return resp.content[0].text

        # Tool results injected as user role with structured content
        tool_results = []
        for block in resp.content:
            if block.type == "tool_use":
                result = fake_get_order(block.input["order_id"])
                tool_results.append({
                    "type": "tool_result",
                    "tool_use_id": block.id,
                    "content": json.dumps(result),
                })
        messages.append({"role": "assistant", "content": resp.content})
        messages.append({"role": "user", "content": tool_results})

print(run_agent("Where is my order #ORD-1234?"))
# "Your order #ORD-1234 has shipped and is expected to arrive on Feb 10."

# WRONG: embedding raw string tool results confuses the model about structure
messages.append({"role": "user", "content": "Order data: " + str(result)})

# CORRECT: use structured content blocks for tool results
messages.append({
    "role": "user",
    "content": [{
        "type": "tool_result",
        "tool_use_id": tool_use_id,
        "content": json.dumps(result),  # always JSON string, not Python repr
    }]
})
